import grpc
import time
import concurrent.futures

import microservice_pb2 as pb2
import microservice_pb2_grpc as pb2_grpc

_ONE_DAY_IN_SECONDS = 60 * 60 * 24

class AuthServicer(pb2_grpc.AuthServiceServicer):
    def Login(self, request, context):
        print(f"Server received Login request for user: {request.username}")
        if request.username == "testuser" and request.password == "testpass":
            return pb2.LoginResponse(
                success=True,
                token="mock_auth_token_123",
                message="Login successful"
            )
        else:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details("Invalid credentials")
            return pb2.LoginResponse(
                success=False,
                token="",
                message="Invalid username or password"
            )

class DataServicer(pb2_grpc.DataServiceServicer):
    def GetUserProfile(self, request, context):
        print(f"Server received GetUserProfile request for user_id: {request.user_id}")
        # In a real scenario, validate auth_token
        if request.auth_token == "mock_auth_token_123":
            if request.user_id == "user123":
                return pb2.GetUserProfileResponse(
                    success=True,
                    user_id="user123",
                    username="Alice",
                    email="alice@example.com",
                    message="Profile retrieved successfully"
                )
            else:
                context.set_code(grpc.StatusCode.NOT_FOUND)
                context.set_details("User not found")
                return pb2.GetUserProfileResponse(
                    success=False,
                    user_id=request.user_id,
                    username="",
                    email="",
                    message="User with provided ID not found"
                )
        else:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details("Invalid or expired authentication token")
            return pb2.GetUserProfileResponse(
                success=False,
                user_id=request.user_id,
                username="",
                email="",
                message="Authentication failed"
            )

def serve():
    server = grpc.server(concurrent.futures.ThreadPoolExecutor(max_workers=10))
    pb2_grpc.add_AuthServiceServicer_to_server(AuthServicer(), server)
    pb2_grpc.add_DataServiceServicer_to_server(DataServicer(), server)
    server.add_insecure_port('[::]:50051')
    server.start()
    print("gRPC Server started on port 50051. Waiting for requests...")
    try:
        while True:
            time.sleep(_ONE_DAY_IN_SECONDS)
    except KeyboardInterrupt:
        server.stop(0)
        print("gRPC Server stopped.")

if __name__ == '__main__':
    serve()

