    with grpc.insecure_channel('localhost:50051') as channel:
        auth_stub = pb2_grpc.AuthServiceStub(channel)
        data_stub = pb2_grpc.DataServiceStub(channel)

        print("--- Testing Auth Service ---")

        # Successful login
        print("\nAttempting successful login...")
        login_request = pb2.LoginRequest(username="testuser", password="testpass")
        login_response = auth_stub.Login(login_request)
        print(f"Login Response: Success={login_response.success}, Token={login_response.token}, Message='{login_response.message}'")

        # Failed login
        print("\nAttempting failed login (wrong password)...")
        failed_login_request = pb2.LoginRequest(username="testuser", password="wrongpass")
        try:
            failed_login_response = auth_stub.Login(failed_login_request)
            print(f"Login Response: Success={failed_login_response.success}, Message='{failed_login_response.message}'")
        except grpc.RpcError as e:
            print(f"Login Failed: {e.code().name} - {e.details()}")

        print("\n--- Testing Data Service ---")

        # Retrieve profile with valid token and user ID
        if login_response.success:
            print("\nAttempting to get user profile with valid token...")
            get_profile_request = pb2.GetUserProfileRequest(user_id="user123", auth_token=login_response.token)
            profile_response = data_stub.GetUserProfile(get_profile_request)
            print(f"Get Profile Response: Success={profile_response.success}, UserID={profile_response.user_id}, Username={profile_response.username}, Email={profile_response.email}, Message='{profile_response.message}'")

            # Retrieve non-existent user profile
            print("\nAttempting to get non-existent user profile...")
            get_non_existent_profile_request = pb2.GetUserProfileRequest(user_id="user456", auth_token=login_response.token)
            try:
                non_existent_profile_response = data_stub.GetUserProfile(get_non_existent_profile_request)
                print(f"Get Profile Response: Success={non_existent_profile_response.success}, Message='{non_existent_profile_response.message}'")
            except grpc.RpcError as e:
                print(f"Get Profile Failed: {e.code().name} - {e.details()}")
        else:
            print("\nSkipping data service tests due to failed login.")

        # Retrieve profile with invalid token
        print("\nAttempting to get user profile with invalid token...")
        invalid_token_request = pb2.GetUserProfileRequest(user_id="user123", auth_token="invalid_token")
        try:
            invalid_token_profile_response = data_stub.GetUserProfile(invalid_token_request)
            print(f"Get Profile Response: Success={invalid_token_profile_response.success}, Message='{invalid_token_profile_response.message}'")
        except grpc.RpcError as e:
            print(f"Get Profile Failed: {e.code().name} - {e.details()}")

